import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { LoansService } from "src/app/core/services/loans.service";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import * as customValidators from "src/app/core/validators/custom-validators";
import { GetLoanCreationInformationForCancelByLoanKey } from "src/app/views/Models/Loan/GetLoanCreationInformationForCancelByLoanKey";
import { ReferencesService } from "src/app/core/services/references.service";
import { LoanRejRef } from "src/app/views/Models/Loan/LoanInfo";
import { CancelLoanCreation } from "src/app/views/Models/Loan/CancelLoanCreation";
import { HttpErrorResponse } from "@angular/common/http";

interface ClientSearchSection {
  visible: boolean;
  clientInformation: SearchResult;
}
interface ReadOnlyInformation {
  loanCode: number;
  clientName: string;
  loanAmount: number;
  installmentsNumber: number;
  periodLength: number;
  periodTypeName: string;
  issuingBankName: string;
  voucher: string;
  officerName: string;
  creationDate: string;
  clientTypeName: string;
  loanNotes?: string;
}
interface LoanSection {
  formGroup: FormGroup;
  visible: boolean;
  checkIfInputsValid: boolean;
  readonlyInformation: ReadOnlyInformation;
}
interface DatabaseResponses {
  getLoanRejection: LoanRejRef[];
  GetLoanCreationInformationForCancelByLoanKey: GetLoanCreationInformationForCancelByLoanKey;
}
@Component({
  selector: "app-cancel-loan-creation",
  templateUrl: "./cancel-loan-creation.page.html",
  styleUrls: ["./cancel-loan-creation.page.scss"],
})
export class CancelLoanCreationPage implements OnInit {
  constructor(
    private alertService: AlertService,
    private formBuilder: FormBuilder,
    private loanService: LoansService,
    private referenceService: ReferencesService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  clientSearchCardSection: ClientSearchSection;
  loanSection: LoanSection;
  databaseResponses: DatabaseResponses;
  //#endregion

  get readOnlyInformation() {
    return this.loanSection.readonlyInformation;
  }
  async ngOnInit() {
    this.initializeForms();
    this.databaseResponses.getLoanRejection =
      await this.referenceService.GetRejActive();
  }
  initializeForms() {
    this.clientSearchCardSection = {
      visible: true,
      clientInformation: null,
    };
    this.loanSection = {
      checkIfInputsValid: false,
      readonlyInformation: null,
      visible: false,
      formGroup: this.formBuilder.group({
        cancellationDate: [
          null,
          customValidators.dateTypeStringValidator({ required: true }),
        ],
        rejectionType: [
          null,
          customValidators.rejectionTypeReasonValidator({ required: true }),
        ],
        loanNotes: [""],
      }),
    };
    this.databaseResponses = {
      GetLoanCreationInformationForCancelByLoanKey: null,
      getLoanRejection: [],
    };
  }
  async clientSelected(searchResult: SearchResult) {
    try {
      this.showLoader = true;
      this.clientSearchCardSection.clientInformation = searchResult;
      const loanInformation = await this.loanService
        .getLoanCreationInformationForCancelByLoanKey(
          Number(searchResult.loan_key)
        )
        .toPromise();
      this.databaseResponses.GetLoanCreationInformationForCancelByLoanKey =
        loanInformation;
      this.loanSection.readonlyInformation =
        this.extractReadOnlyInformation(loanInformation);
      this.clientSearchCardSection.visible = false;
      this.loanSection.visible = true;
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  extractReadOnlyInformation(
    loanInformation: GetLoanCreationInformationForCancelByLoanKey
  ): ReadOnlyInformation {
    return {
      clientName: loanInformation.clientName,
      installmentsNumber: loanInformation.installmentsNumber,
      creationDate: loanInformation.comDecDate,
      issuingBankName: loanInformation.bankName,
      loanAmount: loanInformation.loanAmount,
      clientTypeName: loanInformation.clientTypeName,
      loanCode: loanInformation.loanCode,
      officerName: loanInformation.officerName,
      periodLength: loanInformation.periodLength,
      periodTypeName: loanInformation.periodTypeDescription,
      voucher: loanInformation.loanVoucher,
      loanNotes: loanInformation.loanNotes,
    };
  }
  async cancelLoanButton() {
    try {
      this.loanSection.checkIfInputsValid = true;
      if (!this.loanSection.formGroup.valid) return;
      if (!(await this.alertService.SaveAlert())) return;
      this.showLoader = true;
      const { value } = this.loanSection.formGroup;
      const request: CancelLoanCreation = {
        applicationKey:
          this.databaseResponses.GetLoanCreationInformationForCancelByLoanKey
            .applicationKey,
        comDecDate: value.cancellationDate,
        loanRejectionCode: value.rejectionType,
        uucLoanApplication:
          this.databaseResponses.GetLoanCreationInformationForCancelByLoanKey
            .loanApplicationUuc,
        loanNotes: value.loanNotes,
      };
      await this.loanService.cancelLoanCreation(request).toPromise();
      await this.alertService.showAlertConfirm("تم الحفظ بنجاح", true);
    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }
  backButton() {
    if (this.loanSection.visible) {
      this.loanSection.checkIfInputsValid = false;
      this.loanSection.readonlyInformation = null;
      this.loanSection.visible = false;
      this.loanSection.formGroup.reset();
      this.clientSearchCardSection = {
        clientInformation: null,
        visible: true,
      };
    }
  }
  private handleError(error: unknown) {
    let errorMessage: string;

    if (error instanceof HttpErrorResponse) {
      errorMessage = JSON.stringify(error.error);
    } else if (error instanceof Error) {
      errorMessage = error.message;
    } else {
      errorMessage = String(error);
    }

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
